
// ═══════════════════════════════════════════════════════════════
// 🚀 N8N AUTO-DEPLOY VIA CONSOLE
// ═══════════════════════════════════════════════════════════════

console.log('🚀 Iniciando deploy automatizado...');

// Workflow completo (autocontido com todos os códigos)
const workflowBase64 = '';

// Decode
const workflowJSON = JSON.parse(atob(workflowBase64));

console.log('📝 Workflow:', workflowJSON.name);
console.log('📊 Nodes:', workflowJSON.nodes.length);

// Import via API
fetch('/rest/workflows', {
  method: 'POST',
  headers: {
    'Content-Type': 'application/json'
  },
  body: JSON.stringify(workflowJSON),
  credentials: 'include'
})
.then(response => response.json())
.then(data => {
  console.log('✅ Workflow importado!');
  console.log('   ID:', data.id);
  console.log('   Nome:', data.name);
  
  // Ativar automaticamente
  console.log('📝 Ativando workflow...');
  fetch('/rest/workflows/' + data.id, {
    method: 'PATCH',
    headers: {
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({ active: true }),
    credentials: 'include'
  })
  .then(() => {
    console.log('✅ Workflow ativado!');
    alert('✅ Deploy completo! Workflow ativado e funcionando 24/7.');
    window.location.href = '/workflow/' + data.id;
  });
})
.catch(error => {
  console.error('❌ Erro:', error);
  alert('❌ Erro: ' + error.message);
});
